 1	import React, { FC, useState } from 'react';
 2	
 3	import HelpTextIcon from '@kubevirt-utils/components/HelpTextIcon/HelpTextIcon';
 4	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 5	import {
 6	  ExpandableSection,
 7	  ExpandableSectionToggle,
 8	  Flex,
 9	  FlexItem,
10	  Skeleton,
11	} from '@patternfly/react-core';
12	
13	import { useDrawerContext } from '../hooks/useDrawerContext';
14	
15	import { CustomizeSource } from './CustomizeSource/CustomizeSource';
16	
17	const StorageSection: FC = () => {
18	  const { t } = useKubevirtTranslation();
19	  const { template, templateDataLoaded, vm } = useDrawerContext();
20	
21	  const [storageFieldsExpanded, setStorageFieldsExpanded] = useState<boolean>(true);
22	
23	  const loaded = vm && templateDataLoaded;
24	  return (
25	    <>
26	      <Flex>
27	        <FlexItem spacer={{ default: 'spacerNone' }}>
28	          <ExpandableSectionToggle
29	            data-test-id="expandable-customize-source-section"
30	            isExpanded={loaded && storageFieldsExpanded}
31	            onToggle={() => setStorageFieldsExpanded(!storageFieldsExpanded)}
32	          >
33	            {t('Storage')}
34	          </ExpandableSectionToggle>
35	        </FlexItem>
36	        <FlexItem>
37	          <HelpTextIcon
38	            bodyContent={t(
39	              'You can customize the Templates storage by overriding the original parameters',
40	            )}
41	          />
42	        </FlexItem>
43	      </Flex>
44	      <ExpandableSection
45	        data-test-id="expandable-storage-section"
46	        isDetached
47	        isExpanded={storageFieldsExpanded}
48	        isIndented
49	      >
50	        {loaded ? <CustomizeSource template={template} /> : <Skeleton />}
51	      </ExpandableSection>
52	    </>
53	  );
54	};
55	
56	export default StorageSection;

